function base64url(input) {
  return Buffer.from(input)
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

function sha256B64Url(str) {
  const hash = crypto.createHash('sha256').update(str).digest();
  return hash
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/g, '');
}

function randomString(bytes = 32) {
  return base64url(crypto.randomBytes(bytes));
}

function httpBasicAuthHeader(clientId, clientSecret) {
  const token = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');
  return `Basic ${token}`;
}

async function exchangeCodeForTokens({ code, code_verifier }) {
  const params = new URLSearchParams();
  params.set('grant_type', 'authorization_code');
  params.set('code', code);
  params.set('redirect_uri', REDIRECT_URI);
  params.set('client_id', CLIENT_ID);
  params.set('code_verifier', code_verifier);

  const res = await fetch(TOKEN_ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: httpBasicAuthHeader(CLIENT_ID, CLIENT_SECRET)
    },
    body: params.toString()
  });

  const text = await res.text();
  let json;
  try {
    json = JSON.parse(text);
  } catch {
    const err = new Error('Token endpoint returned non-JSON response');
    err.status = res.status;
    err.body = text;
    throw err;
  }

  if (!res.ok) {
    const err = new Error('Token endpoint error');
    err.status = res.status;
    err.body = json;
    throw err;
  }

  return json;
}

function buildAuthorizationUrl(req) {
  const state = randomString(16);
  const nonce = randomString(16);
  const code_verifier = randomString(32);
  const code_challenge = sha256B64Url(code_verifier);

  req.session.oidc = {
    state,
    nonce,
    code_verifier,
    createdAt: Date.now()
  };

  const url = new URL(AUTHORIZATION_ENDPOINT);
  url.searchParams.set('response_type', 'code');
  url.searchParams.set('client_id', CLIENT_ID);
  url.searchParams.set('redirect_uri', REDIRECT_URI);
  url.searchParams.set('scope', SCOPES);
  url.searchParams.set('state', state);
  url.searchParams.set('nonce', nonce);
  url.searchParams.set('code_challenge', code_challenge);
  url.searchParams.set('code_challenge_method', 'S256');
  return url.toString();
}

function requireAuth(req, res, next) {
  if (req.session && req.session.user) return next();
  res.redirect('/login');
}

app.get('/', (req, res) => {
  if (req.session.user) {
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.end(
      `<h1>Home</h1>
       <p>Logged in as: <strong>${escapeHtml(req.session.user.sub || '')}</strong></p>
       <pre>${escapeHtml(JSON.stringify(req.session.user, null, 2))}</pre>
       <p><a href="/profile">Profile</a> | <a href="/logout">Logout</a></p>`
    );
  } else {
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.end(`<h1>Home</h1><p><a href="/login">Login</a></p>`);
  }
});

app.get('/login', (req, res) => {
  const authUrl = buildAuthorizationUrl(req);
  res.redirect(authUrl);
});

app.get('/oidc/callback', async (req, res) => {
  try {
    const { code, state, error, error_description } = req.query;

    if (error) {
      res.status(400).send(`OIDC error: ${escapeHtml(String(error))} ${escapeHtml(String(error_description || ''))}`);
      return;
    }

    if (!code || !state) {
      res.status(400).send('Missing code/state');
      return;
    }

    const oidc = req.session.oidc;
    if (!oidc || !oidc.state || state !== oidc.state) {
      res.status(400).send('Invalid state');
      return;
    }

    const tokenSet = await exchangeCodeForTokens({
      code: String(code),
      code_verifier: oidc.code_verifier
    });

    const id_token = tokenSet.id_token;
    if (!id_token) {
      res.status(400).send('No id_token in token response');
      return;
    }

    const decoded = jwt.decode(id_token, { complete: true });
    if (!decoded || !decoded.payload) {
      res.status(400).send('Failed to decode id_token');
      return;
    }

    const claims = decoded.payload;

    if (claims.iss !== ISSUER) {
      res.status(400).send('Invalid issuer');
      return;
    }

    if (claims.nonce && oidc.nonce && claims.nonce !== oidc.nonce) {
      res.status(400).send('Invalid nonce');
      return;
    }

    req.session.user = {
      ...claims,
      _id_token: id_token,
      _access_token: tokenSet.access_token,
      _refresh_token: tokenSet.refresh_token,
      _token_type: tokenSet.token_type,
      _expires_in: tokenSet.expires_in,
      _received_at: Date.now()
    };

    delete req.session.oidc;
    res.redirect('/');
  } catch (e) {
    res.status(500).send(`Callback failed: ${escapeHtml(e && e.message ? e.message : String(e))}`);
  }
});

